# par - the Par object that has changed
# val - the current value
# prev - the previous value
# 
# Make sure the corresponding toggle is enabled in the Parameter Execute DAT.

def onValueChange(par, prev):
	# use par.eval() to get current value
	if par.name == 'Reportanalog':
		parent.Firmata.ReportAnalog(state=par.eval())
	elif par.name == 'Reportdigital':
		parent.Firmata.ReportDigital(state=par.eval())
	elif par.name.startswith('Reportpin'):
		parent.Firmata.ReportAnalog(state=par.eval(), pin=tdu.digits(par.name))
	elif par.name.startswith('Reportport'):
		parent.Firmata.ReportDigital(state=par.eval(), port=tdu.digits(par.name))
	elif par.name.startswith('Modepin'):
		pin = tdu.digits(par.name)
		mode = int(par.eval())
		parent.Firmata.SetMode(pin=pin, mode=mode)
	elif par.name.startswith('Valpin'):
		pin = tdu.digits(par.name)
		value = par.eval()
		parent.Firmata.SetValue(pin, value)
	elif par.name == 'Samplinginterval':
		parent.Firmata.SetSampling(int(par.eval()))
	return

def onPulse(par):
	if par.name == 'Queryver':
		parent.Firmata.QueryVersion()
	elif par.name == 'Querycap':
		parent.Firmata.QueryCapabilities()
	elif par.name == 'Querystates':
		parent.Firmata.QueryState()
	elif par.name == 'Queryanalog':
		parent.Firmata.QueryAnalogMap()
	elif par.name == 'Reset':
		parent.Firmata.Reset()
	return
